WITH RECURSIVE task_path AS ( -- 递归基础：从当前任务开始 SELECT t.task_id, t.parent_task_id, t.task_name, t.task_status, t.task_depth, t.report_frequency, t.create_user_id, t.create_time, cu.nick_name AS createUserNickName, cu.user_name AS createUserName, te.user_id AS executorUserId, 0 as level FROM task t INNER JOIN task_executor te ON t.task_id = te.task_id LEFT JOIN sys_user cu ON t.create_user_id = cu.user_id WHERE t.task_id = #{taskId}
UNION ALL
-- 递归查询：向上查找父任务 SELECT p.task_id, p.parent_task_id, p.task_name, p.task_status, p.task_depth, p.report_frequency, p.create_user_id, p.create_time, cu.nick_name AS createUserNickName, cu.user_name AS createUserName, te.user_id AS executorUserId, tp.level + 1 FROM task p INNER JOIN task_executor te ON p.task_id = te.task_id LEFT JOIN sys_user cu ON p.create_user_id = cu.user_id INNER JOIN task_path tp ON p.task_id = tp.parent_task_id ) SELECT task_id, parent_task_id, task_name, task_status, task_depth, report_frequency, create_user_id, create_time, createUserNickName, createUserName, executorUserId, (SELECT COUNT(*) FROM task sub WHERE sub.parent_task_id = task_path.task_id) as subTaskCount, (SELECT COUNT(*) FROM task sub WHERE sub.parent_task_id = task_path.task_id AND sub.task_status >= 3) as completedSubTaskCount, (SELECT MAX(tr.report_time) FROM task_report tr WHERE tr.task_id = task_path.task_id) AS lastReportTime FROM task_path ORDER BY level DESC
